import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import logoAgro from '../../assets/logoAgro.png';
import { Mail, Lock, Shield } from 'lucide-react';
import {Link} from 'react-router-dom';
import './Login.css';

const Login = () => {
    const navigate = useNavigate(); 
    const [email, setEmail] = useState('');
    const [password, setPassword] = useState('');
    const [verificationCode, setVerificationCode] = useState('');
    const [segundos, setSegundos] = useState(60);

    React.useEffect(() => {
        if (segundos > 0) {
            const timer = setTimeout(() => setSegundos(segundos - 1), 1000);
            return () => clearTimeout(timer);
        }
    }, [segundos]);

    const handleSubmit = (e) => {
        e.preventDefault();
        console.log("Dados enviados: ", { email, password, verificationCode });
        navigate('/dashboard');
    };

    return (
        <div className="Login-container">
            <div className="login-form">
                <h2>Login</h2>
                <form onSubmit={handleSubmit}>
                    <div className="input-group">
                        <label htmlFor="email">E-mail</label>
                        <div className="input-with-icon">
                            <Mail className="icon" size={20} />
                            <input type="email" id="email" placeholder="exemplo@gmail.com" value={email} onChange={(e) => setEmail(e.target.value)} required />
                        </div>
                    </div>
                    <div className="input-group">
                        <label htmlFor="password">Senha</label>
                        <div className="input-with-icon">
                            <Lock className="icon" size={20} />
                            <input type="password" d="password" placeholder="Digite sua senha" value={password} onChange={(e) => setPassword(e.target.value)} required />
                        </div>
                    </div>
                    <div className="input-group">
                        <label htmlFor="verificationCode">Código de Verificação</label>
                        <span className="resend-code">Reenviar código em </span>
                        <div className="input-with-icon">
                            <Shield className="icon" size={20} />
                            <input type="text" id="verificationCode" placeholder="Digite o código" maxLength="6" value={verificationCode}onChange={(e) => setVerificationCode(e.target.value)}required />
                        </div>
                    </div>
                    <Link to="/recuperar" className="forgot-password-link">Esqueci minha senha</Link>
                    <button type="submit" className="button">Entrar</button>
                </form>

                <div className="login-footer">
                    <p>Não tem uma conta? <Link to="/cadastro" className="forgot-password-links">Cadastre-se</Link></p>
                </div>
            </div>

            <div className="login-image">
                <img src={logoAgro} alt="Logo do Agromonitor" />
            </div>
        </div>
    );
};

export default Login;
